() => {
  var b64 = '';
  var bin = atob(b64);
  var arr = new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i);
  var blob = new Blob([arr], {type:'image/jpeg'});
  var nonce = wpApiSettings.nonce;
  return fetch('/wp-json/wp/v2/media', {
    method:'POST',
    credentials:'include',
    headers:{'X-WP-Nonce':nonce,'Content-Type':'image/jpeg','Content-Disposition':'attachment; filename="tamanhos-unissex.jpeg"'},
    body: blob
  }).then(r=>r.json()).then(d=>({id:d.id, url:d.source_url, status:d.code||'ok'}));
}